                                        <?php foreach ($groups as $group): ?>
                                        <?php
                                        $categories = $db->prepare("
                                            SELECT * FROM forum_categories
                                            WHERE group_id = ?
                                            ORDER BY id ASC
                                        ");
                                        $categories->execute([$group['id']]);
                                        ?>
                                        <tr>
                                            <td class="forumHeaderBackgroundAlternate" colspan="5" height="20">
                                                <a class="forumTitle" href="/Forum/ShowForumGroup.aspx?GroupID=<?=$group['id']?>">
                                                    <?=htmlspecialchars($group['name'])?>
                                                </a>
                                            </td>
                                        </tr>
                                        <?php foreach ($categories as $category): ?>
                                        <?php
                                        $threadCount = $db->prepare("
                                            SELECT COUNT(*) FROM forum_threads
                                            WHERE category_id = ?
                                        ");
                                        $threadCount->execute([$category['id']]);
                                        $threads = $threadCount->fetchColumn();

                                        $postCount = $db->prepare("
                                        SELECT COUNT(*) FROM forum_replies r
                                        JOIN forum_threads t ON r.thread_id = t.id
                                        WHERE t.category_id = ?
                                        ");
                                        $postCount->execute([$category['id']]);
                                        $replies = $postCount->fetchColumn();

                                        $totalPosts = $threads + $replies;

                                        $lastPost = $db->prepare("
                                        SELECT t.id, t.title, r.created_at
                                        FROM forum_replies r
                                        JOIN forum_threads t ON r.thread_id = t.id
                                        WHERE t.category_id = ?
                                        ORDER BY r.created_at DESC
                                        LIMIT 1
                                        ");
                                        $lastPost->execute([$category['id']]);
                                        $last = $lastPost->fetch();
                                        ?>
                                        <tr style="font-size: 12px;">
                                        <td class="forumRow" align="center" width="34">
                                        <img src="/images/forum_status.gif" width="34">
                                        </td>

                                        <td class="forumRow" width="80%">
                                        <a class="forumTitle" href="/Forum/ShowForum.aspx?ForumID=<?=$category['id']?>">
                                        <?=htmlspecialchars($category['name'])?>
                                        </a>

                                        <span class="normalTextSmall">
                                        <br>
                                        <?=htmlspecialchars($category['description'])?>
                                        </span>
                                        </td>

                                        <td class="forumRowHighlight" align="center">
                                        <span class="normalTextSmaller"><?=$threads?></span>
                                        </td>

                                        <td class="forumRowHighlight" align="center">
                                        <span class="normalTextSmaller"><?=$totalPosts?></span>
                                        </td>

                                        <td class="forumRowHighlight" align="center">
                                        <span class="normalTextSmaller">
                                        <?php if($last): ?>
                                        <b><?=date("M d, h:i A", strtotime($last['created_at']))?></b>
                                        <?php else: ?>
                                        No posts
                                        <?php endif; ?>
                                        </span>
                                        </td>
                                        <?php endforeach; ?>
                                        </tr>
                                        <?php endforeach ?>
